import { apiClient, UserResponse, ApiError } from './apiClient';

type UserWithBalance = {
  id: string;
  name: string;
  balance: number;
};

export async function getUserWithBalance(userId: string): Promise<UserWithBalance> {
  try {
    const user = await apiClient.get<UserResponse>(`/users/${userId}`);
    return {
      id: user.id,
      name: user.name,
      balance: user.balance,
    };
  } catch (error) {
    const err = error as ApiError;

    if (err.status === 404) {
      throw Object.assign(new Error('User not found'), { status: 404 });
    }

    throw err;
  }
}

export function normalizePhone(raw: string): string {
  const input = raw.trim();

  if (input.length === 0) {
    throw new Error('phone is empty');
  }

  // Remove spaces, dashes and parentheses.
  const digits = input.replace(/[^0-9+]/g, '');

  // Already normalized: +7XXXXXXXXXX
  if (/^\+7\d{10}$/.test(digits)) {
    return digits;
  }

  // Replace leading 8 or 7 with +7
  if (/^[78]\d{10}$/.test(digits)) {
    return `+7${digits.slice(1)}`;
  }

  throw new Error('invalid phone');
}

export type OrderItem = {
  id: string;
  price: number;
  quantity: number;
};

export type DiscountCoupon = {
  code: string;
  percent: number; // 0-100
};

export type CalculateOrderTotalOptions = {
  items: OrderItem[];
  shippingCost: number;
  freeShippingThreshold?: number;
  coupon?: DiscountCoupon | null;
};

export function calculateOrderTotal(options: CalculateOrderTotalOptions): number {
  const { items, shippingCost, freeShippingThreshold, coupon } = options;

  if (shippingCost < 0) {
    throw new Error('shippingCost must be non-negative');
  }

  const itemsTotal = items.reduce((sum, item) => {
    if (item.price < 0 || item.quantity < 0) {
      throw new Error('item price and quantity must be non-negative');
    }
    return sum + item.price * item.quantity;
  }, 0);

  let total = itemsTotal;

  if (coupon && coupon.percent > 0) {
    const percent = Math.min(coupon.percent, 100);
    total = total * (1 - percent / 100);
  }

  let finalShipping = shippingCost;
  if (typeof freeShippingThreshold === 'number' && total >= freeShippingThreshold) {
    finalShipping = 0;
  }

  return Math.round((total + finalShipping) * 100) / 100;
}

import { calculateOrderTotal } from '../calculateOrderTotal';

describe('calculateOrderTotal', () => {
  it('calculates total for simple order without discounts', () => {
    // Arrange
    const total = calculateOrderTotal({
      items: [
        { id: '1', price: 100, quantity: 1 },
        { id: '2', price: 50, quantity: 2 },
      ],
      shippingCost: 20,
    });

    // Assert
    expect(total).toBe(220);
  });
});

